import { useState } from "react";
import "./App.css";
import SearchBar from "./components/searchbar";
import ContactForm from "./components/ContactCard";
import { FaPencilAlt } from "react-icons/fa";

function App() {

  const initialContacts = [
    { id: 1, name: "Maria Siddiqua", phone: "03364111054", email: "mariasiddiqua21@gmail.com" },
    { id: 2, name: "Ali Khan", phone: "03001234567", email: "ali@email.com" },
    { id: 3, name: "Sara Ahmed", phone: "03111234567", email: "sara@email.com" }
  ];

  const [contacts, setContacts] = useState(initialContacts);
  const [selectedContact, setSelectedContact] = useState(null);
  const [search, setSearch] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);

  const openAddForm = () => {
    setSelectedContact(null);
    setIsModalOpen(true);
  };

  const openEditForm = (contact) => {
    setSelectedContact(contact);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
  };

  const saveContact = (contactData) => {
    if (selectedContact) {
      setContacts(
        contacts.map(c =>
          c.id === selectedContact.id ? { ...contactData, id: c.id } : c
        )
      );
    } else {
      setContacts([...contacts, { ...contactData, id: Date.now() }]);
    }
    closeModal();
  };

  const deleteContact = () => {
    setContacts(contacts.filter(c => c.id !== selectedContact.id));
    closeModal();
  };

  const filteredContacts = contacts.filter(contact =>
    contact.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="app">

      <h1>Contact Book</h1>
      <p>Manage your contacts easily</p>
      <div className="top-bar">
        <SearchBar search={search} setSearch={setSearch} />
        <button className="add-btn" onClick={openAddForm}>
          + Add Contact
        </button>
      </div>

      {filteredContacts.map(contact => (
        <div key={contact.id} className="contact-row">
          <span>{contact.name}</span>
          <FaPencilAlt className="edit-icon" onClick={() => openEditForm(contact)} />
        </div>
      ))}

      {isModalOpen && (
        <div className="modal-overlay">
          <div className="modal-box">
            <ContactForm
              contact={selectedContact}
              onSave={saveContact}
              onDelete={selectedContact ? deleteContact : null}
              onClose={closeModal}
            />
          </div>
        </div>
      )}

    </div>
  );
}

export default App;
